/* ---------- field crew (one specialism each) ---------- */
export const CREW = [
  {id:'CR-01', name:'Ramesh Patil',    type:'pothole'},
  {id:'CR-02', name:'Suresh Yadav',    type:'pothole'},
  {id:'CR-03', name:'Anita Kamble',    type:'garbage_pile'},
  {id:'CR-04', name:'Vikram Shinde',   type:'garbage_pile'},
  {id:'CR-07', name:'Prakash Jadhav',  type:'street_obstruction'},
  {id:'CR-08', name:'Deepak Salunkhe', type:'street_obstruction'}
];
export const CREW_CAPACITY=10;                  // a crew member can carry at most this many OPEN tasks at once
export const CREW_TYPES=['pothole','garbage_pile','street_obstruction']; // specialisms a crew member can hold — no waterlogging crew
export function nextCrewId(){
  const used=new Set(CREW.map(c=>c.id)); let n=1;
  while(used.has('CR-'+String(n).padStart(2,'0')))n++;
  return 'CR-'+String(n).padStart(2,'0');
}
const CREW_EXTRA_KEY='citylens_crew_extra_v1';   // crew members created via signup, kept outside the static seed so they survive the login → dashboard navigation
(function hydrateCrewExtra(){
  try{
    const extra=JSON.parse(localStorage.getItem(CREW_EXTRA_KEY))||[];
    extra.forEach(c=>{ if(!CREW.some(x=>x.id===c.id)) CREW.push(c); });
  }catch{}
})();
export function saveCrewExtra(member){
  try{
    const extra=JSON.parse(localStorage.getItem(CREW_EXTRA_KEY))||[];
    extra.push(member);
    localStorage.setItem(CREW_EXTRA_KEY, JSON.stringify(extra));
  }catch{}
}

/* ---------- ward-level contractor assignment ---------- */
// A ward can be handed to one crew member as its overall contractor — every repairable
// issue in that ward routes to them, regardless of issue type, overriding the per-type
// round-robin below. Persisted so it survives reloads, same pattern as CREW_EXTRA.
const WARD_CREW_KEY='citylens_ward_crew_v1';
function loadWardCrew(){ try{return JSON.parse(localStorage.getItem(WARD_CREW_KEY))||{};}catch{return {};} }
export function saveWardCrew(map){ try{localStorage.setItem(WARD_CREW_KEY, JSON.stringify(map));}catch{} }
export const WARD_CREW = loadWardCrew();   // ward code -> crew id
